"use client";

import ArrowLeftIcon from "@/components/shared/icons/ArrowLeftIcon";
import SearchIcon from "@/components/shared/icons/SearchIcon";
import { useState } from "react";
import clsx from "clsx";
import { useRouter } from "next/navigation";
import { usePlaceStore } from "@/store/place";

const placeholderText = "모임 장소를 선택하세요.";

export default function GatherPlace() {
  const router = useRouter();

  const [isFocused, setIsFocused] = useState(false);
  const [inputValue, setInputValue] = useState("");

  const handleFocus = () => setIsFocused(true);
  const handleBlur = () => setIsFocused(false);
  const handleChange = (event: React.ChangeEvent<HTMLInputElement>) =>
    setInputValue(event.target.value);

  const setSelectedPlace = usePlaceStore((state) => state.setSelectedPlace);

  const handleClick = (place: string) => {
    setSelectedPlace(place);
    router.push("/gatherMake");
  };

  return (
    <div className="pt-[97px] mx-auto h-screen pl-5 bg-[#f4f4f4]">
      <div className="h-12 justify-start items-center gap-1.5 inline-flex mb-[32.5px]">
        <div className="w-10 pl-[17px] pr-[3px] py-2.5 justify-end items-center flex">
          <div className="w-5 h-5 relative flex-col justify-start items-start flex">
            <div>
              <ArrowLeftIcon
                onClick={() => router.back()}
                className="cursor-pointer"
              />
            </div>
          </div>
        </div>
        <div className="grow shrink basis-0 text-neutral-950 text-lg font-semibold font-['Pretendard'] leading-normal">
          장소 검색
        </div>
        <div className="w-11 h-11 relative" />
      </div>
      <div
        className={clsx(
          inputWrapperStyle,
          isFocused ? "border-grayscale-900" : "border-grayscale-300"
        )}
      >
        <SearchIcon />
        <input
          type="text"
          value={inputValue}
          onChange={handleChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
          className={inputStyle}
          placeholder={inputValue.length === 0 ? placeholderText : ""}
        />
      </div>

      <div
        onClick={() => handleClick("빙봉 성수점")}
        className="h-[68px] w-[390px] px-7 py-4 bg-white flex-col justify-start items-start gap-4 inline-flex cursor-pointer"
      >
        <div className="self-stretch justify-start items-center gap-2 inline-flex">
          <div className="grow shrink basis-0 self-stretch justify-start items-start gap-[4.16px] flex">
            <div className="self-stretch flex-col justify-start items-start gap-[4.16px] inline-flex">
              <div className="text-neutral-950 text-sm font-semibold font-['Pretendard'] leading-[18.20px]">
                빙봉 성수점
              </div>
              <div className="text-[#979797] text-xs font-medium font-['Pretendard'] leading-[14px]">
                서울 성동구 서울숲2길 18-14 1층
              </div>
            </div>
          </div>
          <div className="cursor-pointer w-9 h-9 p-[7.20px] bg-[#f6e24b] rounded-[10.80px] justify-center items-center flex">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              xmlnsXlink="http://www.w3.org/1999/xlink"
              width="22"
              height="22"
              viewBox="0 0 22 22"
              fill="none"
            >
              <rect
                x="0.199707"
                y="0.200012"
                width="21.6"
                height="21.6"
                rx="3.6"
                fill="url(#pattern0_236_7524)"
              />
              <defs>
                <pattern
                  id="pattern0_236_7524"
                  patternContentUnits="objectBoundingBox"
                  width="1"
                  height="1"
                >
                  <use
                    xlinkHref="#image0_236_7524"
                    transform="scale(0.00195312)"
                  />
                </pattern>
                <image
                  id="image0_236_7524"
                  width="512"
                  height="512"
                  xlinkHref="data:image/png;base64,"
                />
              </defs>
            </svg>
          </div>
        </div>
      </div>
    </div>
  );
}

const maxWidth = `max-w-[350px]`;
const height = `h-[50px]`;

const inputWrapperStyle = `w-full ${maxWidth} ${height} flex items-center gap-[12px] px-[20px] py-2 bg-grayscale-10 border rounded-full transition-all duration-300 mb-[20px]`;
const inputStyle =
  "flex-grow bg-grayscale-10 outline-none text-B4 text-grayscale-700";
